solution:
function countPositives(nums) {
  // counter starts at zero before the loop
  let count = 0;
  // visit every index from start to end
  for (let i = 0; i < nums.length; i++) {
    // only count strictly positive values — zero is not positive
    if (nums[i] > 0) {
      count++;
    }
  }
  // return the final tally
  return count;
}

