function productArray(nums) {
  // 1 is the identity for multiplication — multiplying by it changes nothing
  let product = 1;
  // visit every index
  for (let i = 0; i < nums.length; i++) {
    // accumulate the product by multiplying in each element
    product *= nums[i];
  }
  // return the final multiplied result
  return product;
}

