function firstEven(nums) {
  // iterate from the start so we find the leftmost match
  for (let i = 0; i < nums.length; i++) {
    // modulo 2 equals 0 means the number divides evenly by 2
    if (nums[i] % 2 === 0) {
      // return immediately — we only want the first one
      return nums[i];
    }
  }
  // signal that no even number was found
  return -1;
}

