function sumOfSquares(nums) {
  // total accumulates the squared values
  let total = 0;
  // visit every index
  for (let i = 0; i < nums.length; i++) {
    // multiply the element by itself to get its square
    total += nums[i] * nums[i];
  }
  // return the final sum
  return total;
}

