solution:
function allPositive(nums) {
  // check each element one by one
  for (let i = 0; i < nums.length; i++) {
    // a single non-positive value disproves the claim — exit early
    if (nums[i] <= 0) {
      return false;
    }
  }
  // every element passed the check
  return true;
}
